/*
  Requirement:
  The gateway shall periodically transmit the current engine speed value
  to the instrument cluster using the most recently received engine speed data.
*/

// ========== Variable declarations ==========
variables {
  message GW_Consolidated_Status1 msgGWConsolidatedStatus1;
  msTimer tmGWConsolidatedStatus1;

  const int cCycleTime = 50;

  int stored_EngineRPM = 0;   // latest received RPM
  int rpmAge = 0;             // freshness counter (timeout handling)

  const int RPM_TIMEOUT_LIMIT = 5; // number of cycles before data is stale
}

// ========== Initialization ==========
on start {
  write("Gateway simulation started.");

  int i;
  for (i = 0; i < 8; i++) {
    msgGWConsolidatedStatus1.byte(i) = 0;
  }

  rpmAge = RPM_TIMEOUT_LIMIT; // initially invalid until first reception

  setTimer(tmGWConsolidatedStatus1, cCycleTime);
}

// ========== Input message handler ==========
on message ECM_Status {

  // Read engine speed from ECM
  stored_EngineRPM = this.EngineRPM;

  // Reset freshness counter → confirms "most recent data"
  rpmAge = 0;
}

// ========== Cyclic transmission ==========
on timer tmGWConsolidatedStatus1 {

  int i;
  for (i = 0; i < 8; i++) {
    msgGWConsolidatedStatus1.byte(i) = 0;
  }

  // -------- Freshness Check --------
  if (rpmAge < RPM_TIMEOUT_LIMIT) {

    // -------- Apply DBC scaling --------
    // Example: scale = 1, offset = 0 (adjust if DBC differs)
    int raw_RPM = stored_EngineRPM;

    if (raw_RPM < 0) raw_RPM = 0;

    // -------- Pack into message --------
    msgGWConsolidatedStatus1.byte(0) = (byte)(raw_RPM & 0xFF);
    msgGWConsolidatedStatus1.byte(1) = (byte)((raw_RPM >> 8) & 0xFF);
  }
  else {
    // -------- Data stale handling --------
    // Option: send 0 or keep last valid (here sending 0)
    msgGWConsolidatedStatus1.byte(0) = 0;
    msgGWConsolidatedStatus1.byte(1) = 0;
  }

  // -------- Transmit message --------
  output(msgGWConsolidatedStatus1);

  // Increment age counter
  rpmAge++;

  // Restart timer
  setTimer(tmGWConsolidatedStatus1, cCycleTime);
}

